INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (11, 117411, 0, 1, "はぁ、レイ様…♡\n流れる姿も麗しいですね。\nずっと見ていられるぅ…", 7, 1, 943, 19430034, 0, 0);
