INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (3, 1, 0.1, "45_yui_shy_loop", "45_yui_shy_in", 0, "", 945, 19450031, 0.1, 1);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (21, "vo_fpc", "", 0, "vo_fpc_30504", "", "", 945, 19450032, "", "");
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (11, 122611, 0, 1, "…うん、やっちゃった…\nおっきなハートマーク…\nやっぱりこれは無しで！\nマコトちゃん食べてくれる！？", 5, 1, 945, 19450033, 0, 0);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (91, 0, "", "", "", "", "", 945, 19450034, "", "");
